ps.pstext:
if !IsFeatureImplemented(FEAT_SME_B16B16) then EndOfDecode(Decode_UNDEF); end;
let a : integer = UInt(Pn);
let b : integer = UInt(Pm);
let n : integer = UInt(Zn);
let m : integer = UInt(Zm);
let da : integer = UInt(ZAda);

CheckStreamingSVEAndZAEnabled();
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let dim : integer{} = VL DIV 16;
let mask1 : bits(PL) = P{}(a);
let mask2 : bits(PL) = P{}(b);
let op1 : bits(VL) = Z{}(n);
let op2 : bits(VL) = Z{}(m);
let op3 : bits(dim*dim*16) = ZAtile{}(da, 16);
var result : bits(dim*dim*16);

for row = 0 to dim-1 do
    for col = 0 to dim-1 do
        let elem2 : bits(16) = op2[col*:16];
        let elem3 : bits(16) = op3[(row*dim+col)*:16];

        if ActivePredicateElement{PL}(mask1, row, 16) &&
               ActivePredicateElement{PL}(mask2, col, 16) then
            let elem1 : bits(16) = BFNeg(op1[row*:16]);
            result[(row*dim+col)*:16] = BFMulAdd_ZA(elem3, elem1, elem2, FPCR());
        else
            result[(row*dim+col)*:16] = elem3;
        end;
    end;
end;

ZAtile{dim*dim*16}(da, 16) = result;
